// Knowledge Base (Horn Clauses)
parent(john, mary).
parent(john, tom).
parent(mary, ann).

ancestor(X, Y) :- parent(X, Y).
ancestor(X, Y) :- parent(X, Z), ancestor(Z, Y).

// Query: ancestor(john, ann)?
// SLD Resolution trace:
// Goal: ancestor(john, ann)
// 1. Match with rule 1: parent(john, ann) - FAIL
// 2. Match with rule 2: parent(john, Z), ancestor(Z, ann)
// → parent(john, mary) succeeds, Z=mary
// → Goal becomes: ancestor(mary, ann)
// → Matches rule 1: parent(mary, ann) - SUCCEEDS!
// → PROOF: ancestor(john, ann) is TRUE

FUNCTION ToCNF(formula):
 // Step 1: Remove implications and biconditional
 F1 = RemoveImplications(formula)
 F2 = RemoveBiconditional(F1)

 // Step 2: Move negations inward (NNF)
 F3 = NegateInward(F2)

 // Step 3: Standardize apart (rename variables)
 F4 = Standardize(F3)

 // Step 4: Skolemize (remove existential quantifiers)
 F5 = Skolemize(F4)

 // Step 5: Drop universal quantifiers
 F6 = DropUniversal(F5)

 // Step 6: Convert to CNF (distribute ∨ over ∧)
 F7 = Distribute(F6)

 // Step 7: Convert to clause set
 Clauses = ConvertToClauses(F7)

 RETURN Clauses

FUNCTION Skolemize(formula):
 // Replace ∃x P(x) with P(f(c1,...cn)) where f is new Skolem function
 // c1...cn are universally quantified variables in scope
 RETURN skolemized_formula

FUNCTION ConvertToClauses(cnf_formula):
 // Each conjunct becomes a clause (set of literals)
 RETURN set_of_clauses
